long long solve(long long n, std::vector<std::vector<long long>> edges) {
    // Build the graph: adj[u] = list of {v, w}
    vector<vector<pair<long long, long long>>> adj(n);
    // Build reverse edges: rev_adj[v] = list of {u, w}
    vector<vector<pair<long long, long long>>> rev_adj(n);
    for (const auto& e : edges) {
        long long u = e[0], v = e[1], w = e[2];
        adj[u].emplace_back(v, w);
        rev_adj[v].emplace_back(u, w);
    }

    // dist[node][used_switch] = min cost
    vector<vector<long long>> dist(n, vector<long long>(2, LLONG_MAX));
    dist[0][0] = 0;

    // priority queue: {current_cost, node, used_switch}
    priority_queue<tuple<long long, long long, bool>, vector<tuple<long long, long long, bool>>, greater<>> pq;
    pq.emplace(0, 0, false);

    while (!pq.empty()) {
        auto [current_dist, u, used] = pq.top();
        pq.pop();

        if (current_dist > dist[u][used]) continue;

        // Explore normal edges
        for (const auto& [v, w] : adj[u]) {
            if (current_dist + w < dist[v][used]) {
                dist[v][used] = current_dist + w;
                pq.emplace(dist[v][used], v, used);
            }
        }

        // If switch hasn't been used yet, explore reversed edges
        if (!used) {
            for (const auto& [v, w] : rev_adj[u]) {
                long long new_dist = current_dist + 2 * w;
                if (new_dist < dist[v][true]) {
                    dist[v][true] = new_dist;
                    pq.emplace(new_dist, v, true);
                }
            }
        }
    }

    long long result = min(dist[n-1][0], dist[n-1][1]);
    return result == LLONG_MAX ? -1 : result;
}

